```javascript
const bibliotheque = {
  livres: [],
  ajouterLivre: function(titre, auteur) {
    this.livres.push({ titre, auteur, disponible: true });
  },
  emprunterLivre: function(titre) {
    const livre = this.livres.find(l => l.titre === titre);
    if (livre && livre.disponible) {
      livre.disponible = false;
      return "Emprunté";
    }
    return "Indisponible";
  },
  retournerLivre: function(titre) {
    const livre = this.livres.find(l => l.titre === titre);
    if (livre) {
      livre.disponible = true;
    }
  },
  listerLivres: function() {
    this.livres.forEach(livre => {
      console.log(`${livre.titre} - ${livre.auteur} - ${livre.disponible ? "Disponible" : "Emprunté"}`);
    });
  }
};

// Test
bibliotheque.ajouterLivre("JavaScript: The Good Parts", "Douglas Crockford");
bibliotheque.ajouterLivre("Clean Code", "Robert C. Martin");
bibliotheque.emprunterLivre("Clean Code");
bibliotheque.listerLivres();
```
